@dataclass(frozen=True)
class _Config:
    base_url: str
    token: Optional[str] = None
    timeout: float = 15.0
    disable_cache: bool = False


def _normalize_base_url(base_url: str) -> str:
    normalized = base_url.rstrip("/")
    if normalized.endswith("/api/v1"):
        normalized = normalized[: -len("/api/v1")]
    return normalized


def _coerce_optional_bool(value: Any) -> Optional[bool]:
    if value is None:
        return None
    if isinstance(value, bool):
        return value
    if isinstance(value, str):
        normalized = value.strip().lower()
        if normalized in {"1", "true", "yes", "on"}:
            return True
        if normalized in {"0", "false", "no", "off"}:
            return False
    if isinstance(value, (int, float)):
        return bool(value)
    return bool(value)

class _HTTP:
    def __init__(self, cfg: _Config):
        self._cfg = cfg
        self._client = httpx.Client(timeout=cfg.timeout, trust_env=False)
        self.last_response_meta: Optional[ResponseMeta] = None

    def _apply_cache_control(
        self,
        method: str,
        params: Dict[str, Any] | None,
        disable_cache: bool | None,
    ) -> Dict[str, Any] | None:
        query = dict(params or {})
        effective_disable_cache = self._cfg.disable_cache if disable_cache is None else disable_cache
        if method.upper() == "GET" and ("_t" not in query or query["_t"] is None) and effective_disable_cache:
            query["_t"] = int(time.time() * 1000)
        return query or None

    def request(
        self,
        method: str,
        path: str,
        *,
        params: Dict[str, Any] | None = None,
        json: Any | None = None,
        headers: Dict[str, str] | None = None,
        disable_cache: bool | None = None,
    ):
        url = self._cfg.base_url.rstrip("/") + path
        headers = headers or {}
        if self._cfg.token:
            headers["Authorization"] = f"Bearer {self._cfg.token}"
        query = self._apply_cache_control(method, params, disable_cache)
        r = self._client.request(method, url, params=query, json=json, headers=headers)
        if r.status_code >= 400:
            err = map_error(r)
            self.last_response_meta = err.meta
            raise err
        self.last_response_meta = extract_meta(r.headers)
        # try json else bytes
        try:
            return r.json()
        except Exception:
            return r.content

